import React, { useEffect, useState } from "react";
import { useParams, Link } from "react-router-dom";
import { useDispatch, useSelector } from "react-redux";
import { getRfqDetail, respondToRfq } from "../../features/b2b/b2bSlice";
import { ArrowLeft, FileText, User, Calendar, MessageSquare, DollarSign } from "lucide-react";
import { Table, Button, Input, message, Card } from "antd";

const RfqDetail = () => {
  const { id } = useParams();
  const dispatch = useDispatch();

  const [quotedPrices, setQuotedPrices] = useState({});
  const [validDays, setValidDays] = useState(7);
  const [adminNotes, setAdminNotes] = useState("");

  const { rfqDetail, isLoading } = useSelector((state) => state.b2b);

  useEffect(() => {
    dispatch(getRfqDetail(id));
  }, [dispatch, id]);

  useEffect(() => {
    if (rfqDetail) {
      const prices = {};
      rfqDetail.items?.forEach((item) => {
        // Default quoted price to targetPrice or product wholesale price
        prices[item.productId] =
          item.targetPrice || item.product?.wholesalePrice || 0;
      });
      setQuotedPrices(prices);
    }
  }, [rfqDetail]);

  const handlePriceChange = (productId, val) => {
    const price = parseFloat(val) || 0;
    setQuotedPrices({ ...quotedPrices, [productId]: price });
  };

  const handleSubmitQuote = () => {
    const adminResponse = rfqDetail.items.map((item) => ({
      productId: item.productId,
      quotedPrice: quotedPrices[item.productId] || 0,
      notes: item.notes || null,
      quantity: item.quantity,
    }));

    dispatch(
      respondToRfq({
        id,
        adminResponse,
        validDays: parseInt(validDays) || 7,
        notes: adminNotes,
      })
    ).then((res) => {
      if (res.meta.requestStatus === "fulfilled") {
        message.success("Quote submitted successfully.");
      } else {
        message.error("Failed to submit quote response.");
      }
    });
  };

  if (isLoading || !rfqDetail) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[400px] opacity-50">
        <div className="w-8 h-8 rounded-full border-2 border-blue-600 border-t-transparent animate-spin mb-4" />
        <p className="font-black text-slate-400 uppercase tracking-widest text-xs">
          Loading RFQ details...
        </p>
      </div>
    );
  }

  const isResponded = ["QUOTED", "ACCEPTED", "REJECTED"].includes(
    rfqDetail.status
  );

  const columns = [
    {
      title: "Requested Product",
      dataIndex: "product",
      render: (product) => (
        <div className="flex flex-col">
          <span className="font-bold text-slate-900 text-sm">
            {product?.title || "Unknown Product"}
          </span>
          <span className="text-[11px] text-slate-400 font-bold uppercase tracking-widest mt-1">
            SKU: {product?.sku || "N/A"} | Generic: {product?.genericName || "N/A"}
          </span>
        </div>
      ),
    },
    {
      title: "Stock Status",
      dataIndex: "product",
      render: (product) => (
        <span className="font-bold text-xs text-slate-600">
          {product?.quantity || 0} In Stock
        </span>
      ),
    },
    {
      title: "Qty Requested",
      dataIndex: "quantity",
      render: (qty, record) => (
        <span className="font-bold text-slate-800 text-sm">
          {qty} <span className="text-[11px] text-slate-400">{record.product?.unitOfSale || "standard"}</span>
        </span>
      ),
    },
    {
      title: "Wholesale List Price",
      dataIndex: "product",
      render: (product) => (
        <span className="font-bold text-slate-800">
          {parseFloat(product?.wholesalePrice || 0).toLocaleString()} ETB
        </span>
      ),
    },
    {
      title: "Target Price (Buyer)",
      dataIndex: "targetPrice",
      render: (target) =>
        target ? (
          <span className="font-bold text-slate-800 bg-slate-50 px-2.5 py-1 rounded-lg border border-slate-100 text-xs">
            {parseFloat(target).toLocaleString()} ETB
          </span>
        ) : (
          <span className="text-slate-400 text-xs">-</span>
        ),
    },
    {
      title: "Quoted Price (Wholesale)",
      dataIndex: "productId",
      render: (productId, record) => {
        if (isResponded) {
          const matchedResponse = rfqDetail.adminResponse?.find(
            (r) => r.productId === productId
          );
          return (
            <span className="font-black text-emerald-600 text-sm">
              {parseFloat(matchedResponse?.quotedPrice || 0).toLocaleString()} ETB
            </span>
          );
        }

        return (
          <Input
            type="number"
            className="w-28 rounded-lg text-center font-bold"
            value={quotedPrices[productId] ?? 0}
            onChange={(e) => handlePriceChange(productId, e.target.value)}
          />
        );
      },
    },
    {
      title: "Line Subtotal (Quoted)",
      render: (_, record) => {
        const qty = record.quantity || 0;
        let price = 0;
        if (isResponded) {
          const matchedResponse = rfqDetail.adminResponse?.find(
            (r) => r.productId === record.productId
          );
          price = parseFloat(matchedResponse?.quotedPrice || 0);
        } else {
          price = quotedPrices[record.productId] || 0;
        }

        return (
          <span className="font-black text-slate-900">
            {(qty * price).toLocaleString()} ETB
          </span>
        );
      },
    },
  ];

  return (
    <div className="space-y-8 pb-12">
      {/* Back Header */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div className="flex items-center gap-4">
          <Link
            to="/admin/b2b/rfq"
            className="p-3 bg-white border border-slate-200 rounded-2xl hover:bg-slate-50 transition-colors shadow-sm"
          >
            <ArrowLeft size={18} className="text-slate-500" />
          </Link>
          <div>
            <span className="text-[11px] font-black text-blue-600 uppercase tracking-[0.2em]">
              Request for Quote details
            </span>
            <h1 className="text-[28px] font-bold text-slate-900 tracking-tight leading-tight">
              RFQ Response Panel
            </h1>
          </div>
        </div>

        <div className="flex items-center gap-3">
          <span
            className={`status-badge ${
              rfqDetail.status === "ACCEPTED"
                ? "success"
                : rfqDetail.status === "REJECTED" || rfqDetail.status === "EXPIRED"
                ? "danger"
                : rfqDetail.status === "QUOTED"
                ? "active"
                : "info"
            }`}
          >
            <div
              className={`w-1.5 h-1.5 rounded-full ${
                rfqDetail.status === "ACCEPTED"
                  ? "bg-emerald-500"
                  : rfqDetail.status === "REJECTED" || rfqDetail.status === "EXPIRED"
                  ? "bg-rose-500"
                  : rfqDetail.status === "QUOTED"
                  ? "bg-blue-500"
                  : "bg-amber-400"
              }`}
            />
            {rfqDetail.status}
          </span>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Core Items Requested */}
        <div className="lg:col-span-2 space-y-8">
          <div className="bg-white rounded-3xl border border-slate-100 p-8 shadow-sm">
            <div className="flex items-center gap-3 mb-6">
              <FileText size={20} className="text-slate-400" />
              <h3 className="text-lg font-black text-slate-900">Items Under Request</h3>
            </div>
            <Table
              columns={columns}
              dataSource={rfqDetail.items || []}
              pagination={false}
              className="modern-table"
              rowKey="productId"
            />
          </div>
        </div>

        {/* Sidebar Info & Quote Submission controls */}
        <div className="space-y-8">
          {/* Card 1: Buyer Profile */}
          <div className="bg-white rounded-3xl border border-slate-100 p-8 shadow-sm space-y-4">
            <div className="flex items-center gap-3 border-b border-slate-50 pb-4">
              <User size={18} className="text-slate-400" />
              <h4 className="font-bold text-slate-800 text-sm">Requester Info</h4>
            </div>
            <div>
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">
                Institution
              </p>
              <p className="font-bold text-slate-900 text-base">
                {rfqDetail.customer?.institutionName || "Individual Buyer"}
              </p>
            </div>
            <div>
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">
                Authorized By
              </p>
              <p className="font-bold text-slate-700 text-sm">
                {rfqDetail.customer?.firstname} {rfqDetail.customer?.lastname}
              </p>
              <p className="text-slate-400 text-xs font-medium mt-0.5">
                {rfqDetail.customer?.email}
              </p>
            </div>
            {rfqDetail.notes && (
              <div className="bg-slate-50 border border-slate-100 p-4 rounded-xl">
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">
                  Buyer Notes
                </p>
                <p className="text-slate-600 text-xs font-semibold leading-relaxed">
                  "{rfqDetail.notes}"
                </p>
              </div>
            )}
          </div>

          {/* Card 2: Send response */}
          <div className="bg-white rounded-3xl border border-slate-100 p-8 shadow-sm space-y-5">
            <div className="flex items-center gap-3 border-b border-slate-50 pb-4">
              <DollarSign size={18} className="text-slate-400" />
              <h4 className="font-bold text-slate-800 text-sm">Supply Quote Terms</h4>
            </div>

            {isResponded ? (
              <div className="space-y-4">
                <div>
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">
                    Validity Duration
                  </p>
                  <p className="font-bold text-slate-700 text-sm">
                    Valid Until: {new Date(rfqDetail.validUntil).toLocaleDateString()}
                  </p>
                </div>
                {rfqDetail.notes && (
                  <div>
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">
                      Admin Notes
                    </p>
                    <p className="text-slate-600 text-xs font-bold bg-slate-50 border border-slate-100 p-3 rounded-xl mt-1">
                      {rfqDetail.notes}
                    </p>
                  </div>
                )}
              </div>
            ) : (
              <div className="space-y-4">
                <div>
                  <label className="text-[11px] font-black text-slate-400 uppercase tracking-widest block mb-2">
                    Quote Validity (Days)
                  </label>
                  <Input
                    type="number"
                    value={validDays}
                    onChange={(e) => setValidDays(e.target.value)}
                    className="h-11 rounded-xl font-bold"
                    placeholder="7"
                  />
                </div>

                <div>
                  <label className="text-[11px] font-black text-slate-400 uppercase tracking-widest block mb-2">
                    Remarks / Terms for Quote
                  </label>
                  <Input.TextArea
                    value={adminNotes}
                    onChange={(e) => setAdminNotes(e.target.value)}
                    rows={4}
                    className="rounded-xl font-medium"
                    placeholder="e.g. Free shipping on this quote. Batch expires Oct 2027."
                  />
                </div>

                <Button
                  type="primary"
                  onClick={handleSubmitQuote}
                  className="bg-blue-600 hover:bg-blue-700 h-11 font-black uppercase text-xs tracking-widest rounded-xl w-full"
                >
                  Send Price Quote
                </Button>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default RfqDetail;
